  ('promotion-c5fb3965-moex-00012', 'promotion-c5fb3965', 'promotion-c5fb3965-moex-114-3082b5f1', 'sub-promotion-c5fb3965-02', NULL, 'single_choice', '關於行政程序法上職務協助之敘述，下列何者正確？', '["行政機關執行職務，由被請求機關協助執行較為經濟時，須組織法規有明文，始得請求職務協助", "被請求機關應考量協助之行為是否在其權限範圍內", "職務協助與委任、委託不同，屬於短暫性之關係，但仍會涉及權限之移轉", "職務協助須公告其協助之事項以及所提供之協助方式"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:49+00:00", "source_pdf_sha1": "74c4580f828f", "answer_pdf_sha1": "52ed235f6cad", "source_family": "moex-gov-tw", "moex": {"exam_code": "114160", "c": "103", "s": "0406", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "114", "exam_name": "114年公務人員升官等考試、114年關務人員升官等考試、114年交通事業郵政人員升資考試、114年交通事業港務人員升資考試", "original_question_number": 6, "answer_corrected": false, "flags": [], "civil_slug": "promotion", "civil_category": "戶政"}'::jsonb, NULL),
  ('promotion-c5fb3965-moex-00013', 'promotion-c5fb3965', 'promotion-c5fb3965-moex-114-3082b5f1', 'sub-promotion-c5fb3965-02', NULL, 'single_choice', '依公務人員考績法及實務見解，有關公務人員考績之敘述，下列何者正確？', '["行政機關對公務人員記大過處分，無懲處權時效之適用", "公務人員不服其服務機關所為考績丙等之評定，應以銓敘部為被告提起行政訴訟", "公務人員之年終考績丁等，效力為一次記兩大過免職", "考績應予免職人員，自確定之日起執行；未確定前，應先行停職"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:49+00:00", "source_pdf_sha1": "74c4580f828f", "answer_pdf_sha1": "52ed235f6cad", "source_family": "moex-gov-tw", "moex": {"exam_code": "114160", "c": "103", "s": "0406", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "114", "exam_name": "114年公務人員升官等考試、114年關務人員升官等考試、114年交通事業郵政人員升資考試、114年交通事業港務人員升資考試", "original_question_number": 7, "answer_corrected": false, "flags": [], "civil_slug": "promotion", "civil_category": "戶政"}'::jsonb, NULL)
